// ProductModal component
function ProductModal({productName, onClose, onNavigate}){
  const p = PRODUCT_DATA[productName];
  React.useEffect(()=>{
    function onKey(e){ if(e.key==="Escape") onClose(); }
    window.addEventListener("keydown",onKey);
    return()=>window.removeEventListener("keydown",onKey);
  },[onClose]);

  if(!p) return(
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-box" style={{background:"#1A2B2E",border:"1px solid rgba(255,255,255,0.1)",padding:32}} onClick={e=>e.stopPropagation()}>
        <div style={{color:"#6E9990",fontSize:14,textAlign:"center",padding:"40px 0"}}>Product details coming soon for <strong style={{color:"#fff"}}>{productName}</strong>.</div>
        <button onClick={onClose} style={{display:"block",margin:"20px auto 0",background:"rgba(99,171,143,0.12)",border:"1px solid rgba(99,171,143,0.3)",borderRadius:100,padding:"9px 22px",color:"#91C4B0",fontSize:12,fontWeight:800,cursor:"pointer",fontFamily:"inherit",letterSpacing:"0.06em",textTransform:"uppercase"}}>Close</button>
      </div>
    </div>
  );

  return(
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-box" style={{background:"linear-gradient(160deg,#152224,#0E1A1C)",border:`1px solid rgba(${p.glow},0.35)`,boxShadow:`0 0 60px rgba(${p.glow},0.15), 0 32px 80px rgba(0,0,0,0.7)`}} onClick={e=>e.stopPropagation()}>

        {/* Close */}
        <button onClick={onClose} style={{position:"absolute",top:16,right:16,width:32,height:32,borderRadius:"50%",background:"rgba(255,255,255,0.07)",border:"1px solid rgba(255,255,255,0.14)",color:"rgba(255,255,255,0.5)",fontSize:16,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",zIndex:2,fontFamily:"inherit",lineHeight:1}}>×</button>

        {/* Header */}
        <div style={{padding:"28px 28px 20px",borderBottom:`1px solid rgba(${p.glow},0.15)`}}>
          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
            <span style={{background:`rgba(${p.glow},0.14)`,border:`1px solid rgba(${p.glow},0.35)`,borderRadius:100,padding:"3px 11px",fontSize:10,fontWeight:800,color:p.color,letterSpacing:"0.1em",textTransform:"uppercase"}}>{p.badge}</span>
          </div>
          <h2 style={{fontSize:"clamp(20px,3vw,28px)",fontWeight:800,color:"#fff",letterSpacing:"-0.03em",lineHeight:1.1,marginBottom:8,fontFamily:"'Syne',sans-serif"}}>
            <span style={{color:p.color}}>{productName}</span>
          </h2>
          <p style={{fontSize:13,color:p.color,opacity:0.75,fontWeight:600,marginBottom:12}}>{p.tagline}</p>
          <p style={{fontSize:13.5,color:"#7AADA0",lineHeight:1.8}}>{p.summary}</p>
        </div>

        {/* Sections (optional) */}
        {p.sections && (
          <div style={{padding:"20px 28px 0",display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
            {p.sections.map((s,i)=>(
              <div key={i} style={{background:`rgba(${p.glow},0.06)`,border:`1px solid rgba(${p.glow},0.15)`,borderRadius:12,padding:"14px 16px"}}>
                <div style={{fontSize:11,fontWeight:800,color:p.color,letterSpacing:"0.08em",textTransform:"uppercase",marginBottom:6}}>{s.title}</div>
                <p style={{fontSize:12,color:"#7AADA0",lineHeight:1.72,margin:0}}>{s.body}</p>
              </div>
            ))}
          </div>
        )}

        {/* Key features */}
        <div style={{padding:"20px 28px 0"}}>
          <div style={{fontSize:10,fontWeight:800,color:`rgba(${p.glow},0.6)`,letterSpacing:"0.12em",textTransform:"uppercase",marginBottom:12}}>Key Features</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"6px 14px"}}>
            {p.highlights.map((h,i)=>(
              <div key={i} style={{display:"flex",alignItems:"flex-start",gap:8}}>
                <span style={{color:p.color,fontSize:11,marginTop:2,flexShrink:0}}>✓</span>
                <span style={{fontSize:12,color:"#B0CEC8",lineHeight:1.55}}>{h}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Related products */}
        {p.relatedIds && p.relatedIds.length > 0 && (
          <div style={{padding:"20px 28px 0"}}>
            <div style={{fontSize:10,fontWeight:800,color:`rgba(${p.glow},0.6)`,letterSpacing:"0.12em",textTransform:"uppercase",marginBottom:10}}>Related Products</div>
            <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
              {p.relatedIds.map(name=>{
                const rel = PRODUCT_DATA[name];
                const rc = rel ? rel.color : "#91C4B0";
                const rg = rel ? rel.glow : "145,196,176";
                return(
                  <button key={name} onClick={()=>onNavigate(name)}
                    style={{background:`rgba(${rg},0.1)`,border:`1px solid rgba(${rg},0.35)`,borderRadius:100,padding:"7px 16px",fontSize:11,fontWeight:800,color:rc,cursor:"pointer",fontFamily:"inherit",letterSpacing:"0.04em",transition:"all 0.2s"}}
                    onMouseEnter={e=>{e.currentTarget.style.background=`rgba(${rg},0.22)`;e.currentTarget.style.borderColor=`rgba(${rg},0.6)`;}}
                    onMouseLeave={e=>{e.currentTarget.style.background=`rgba(${rg},0.1)`;e.currentTarget.style.borderColor=`rgba(${rg},0.35)`;}}
                  >{name} →</button>
                );
              })}
            </div>
          </div>
        )}

        {/* Footer: IPI website link */}
        <div style={{padding:"18px 28px 24px",display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:10}}>
          <span style={{fontSize:10,color:`rgba(${p.glow},0.35)`,fontWeight:600}}>Source: ipintegration.com</span>
          {p.url && (
            <a href={p.url} target="_blank" rel="noopener noreferrer"
              style={{display:"inline-flex",alignItems:"center",gap:6,background:`rgba(${p.glow},0.1)`,border:`1px solid rgba(${p.glow},0.3)`,borderRadius:100,padding:"7px 16px",fontSize:11,fontWeight:800,color:p.color,textDecoration:"none",letterSpacing:"0.04em",transition:"all 0.2s"}}
              onMouseEnter={e=>{e.currentTarget.style.background=`rgba(${p.glow},0.2)`;}}
              onMouseLeave={e=>{e.currentTarget.style.background=`rgba(${p.glow},0.1)`;}}
            >
              View on IPI website ↗
            </a>
          )}
        </div>
      </div>
    </div>
  );
}

