function StackLayerFull({layer, isActive, onToggle, onProduct}){
  return(
    <div className="stack-layer"
      style={{
        background: isActive
          ? layer.bg.replace(/0\.\d+\)/g, m => String(parseFloat(m)*1.6)+')')
          : layer.bg,
        border:`1.5px solid ${isActive ? layer.border : layer.border.replace(/0\.\d+\)/, '0.25)')}`,
        boxShadow: isActive ? `0 0 32px rgba(${layer.glow},0.22), 0 8px 32px rgba(0,0,0,0.4)` : '0 2px 12px rgba(0,0,0,0.3)',
        padding:"0",
        overflow:"hidden",
        cursor:"pointer",
      }}
      onClick={onToggle}
    >
      {/* Main row */}
      <div style={{display:"flex",alignItems:"center",gap:16,padding:"16px 22px",cursor:"pointer"}}>
        {/* Icon */}
        <div style={{width:42,height:42,borderRadius:11,background:`rgba(${layer.glow},0.15)`,border:`1px solid ${layer.color}40`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0,transition:"all 0.25s",boxShadow:isActive?`0 0 14px rgba(${layer.glow},0.4)`:"none"}}>
          {layer.icon}
        </div>
        {/* Label */}
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:15,fontWeight:800,color:isActive?layer.color:"#D0E8E0",letterSpacing:"-0.01em",fontFamily:"'Syne',sans-serif",transition:"color 0.25s",textShadow:isActive?`0 0 16px rgba(${layer.glow},0.6)`:"none"}}>
            {layer.label}
          </div>
          <div style={{fontSize:11,color:isActive?`rgba(${layer.glow},0.7)`:"rgba(110,153,144,0.6)",fontWeight:600,marginTop:2,transition:"color 0.25s"}}>
            {layer.sublabel}
          </div>
        </div>
        {/* Product pills */}
        <div style={{display:"flex",flexWrap:"wrap",gap:6,justifyContent:"flex-end",flex:"0 1 auto",maxWidth:"55%"}}>
          {layer.items.map(item=>{
            const hasDetail = !!PRODUCT_DATA[item];
            return(
              <span key={item} className="stack-pill"
                onClick={hasDetail ? e=>{e.stopPropagation(); onProduct&&onProduct(item);} : undefined}
                style={{
                  color:isActive?layer.color:"rgba(180,210,204,0.65)",
                  borderColor:isActive?`${layer.color}50`:"rgba(255,255,255,0.1)",
                  background:isActive?`rgba(${layer.glow},0.12)`:"rgba(255,255,255,0.05)",
                  cursor:hasDetail?"pointer":"default",
                  position:"relative",
                }}
              >
                {item}{hasDetail && <span style={{marginLeft:4,fontSize:9,opacity:0.6}}>↗</span>}
              </span>
            );
          })}
        </div>
        {/* Expand chevron */}
        <div style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.1)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"all 0.25s",transform:isActive?"rotate(180deg)":"none",color:isActive?layer.color:"rgba(180,210,204,0.4)",fontSize:14}}>
          ▾
        </div>
      </div>

      {/* Expanded description */}
      {isActive && (
        <div style={{padding:"0 22px 18px 80px",animation:"fadeUp 0.25s ease both"}}>
          <div style={{height:1,background:`linear-gradient(90deg,rgba(${layer.glow},0.2),transparent)`,marginBottom:14}}/>
          <p style={{fontSize:13,color:"#7aa09a",lineHeight:1.82}}>{layer.desc}</p>
        </div>
      )}
    </div>
  );
}

function StackLayerSplit({layer, activeId, onToggle, onProduct}){
  const {left, right} = layer;
  return(
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
      {[left,right].map(sub=>{
        const isActive = activeId === sub.id;
        return(
          <div key={sub.id} className="stack-layer"
            style={{
              background: isActive ? sub.bg.replace(/0\.\d+\)/g, m=>String(parseFloat(m)*1.6)+')') : sub.bg,
              border:`1.5px solid ${isActive?sub.border:sub.border.replace(/0\.\d+\)/,'0.25)')}`,
              boxShadow: isActive?`0 0 28px rgba(${sub.glow},0.22),0 8px 28px rgba(0,0,0,0.4)`:'0 2px 12px rgba(0,0,0,0.3)',
              overflow:"hidden",
            }}
            onClick={()=>onToggle(sub.id)}
          >
            <div style={{display:"flex",alignItems:"center",gap:12,padding:"16px 18px",cursor:"pointer"}}>
              <div style={{width:38,height:38,borderRadius:10,background:`rgba(${sub.glow},0.15)`,border:`1px solid ${sub.color}40`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0,boxShadow:isActive?`0 0 12px rgba(${sub.glow},0.4)`:"none"}}>
                {sub.icon}
              </div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontSize:14,fontWeight:800,color:isActive?sub.color:"#D0E8E0",fontFamily:"'Syne',sans-serif",transition:"color 0.25s",textShadow:isActive?`0 0 14px rgba(${sub.glow},0.6)`:"none"}}>{sub.label}</div>
                <div style={{fontSize:10,color:isActive?`rgba(${sub.glow},0.65)`:"rgba(110,153,144,0.55)",fontWeight:600,marginTop:2}}>{sub.sublabel}</div>
              </div>
              <div style={{width:24,height:24,borderRadius:"50%",background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.1)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"transform 0.25s",transform:isActive?"rotate(180deg)":"none",color:isActive?sub.color:"rgba(180,210,204,0.4)",fontSize:12}}>
                ▾
              </div>
            </div>
            {/* Pills */}
            <div style={{display:"flex",flexWrap:"wrap",gap:5,padding:"0 18px 14px"}}>
              {sub.items.map(item=>{
                const hasDetail = !!PRODUCT_DATA[item];
                return(
                  <span key={item} className="stack-pill"
                    onClick={hasDetail ? e=>{e.stopPropagation(); onProduct&&onProduct(item);} : undefined}
                    style={{fontSize:10.5,color:isActive?sub.color:"rgba(180,210,204,0.6)",borderColor:isActive?`${sub.color}50`:"rgba(255,255,255,0.1)",background:isActive?`rgba(${sub.glow},0.12)`:"rgba(255,255,255,0.05)",cursor:hasDetail?"pointer":"default"}}
                  >{item}{hasDetail && <span style={{marginLeft:3,fontSize:9,opacity:0.6}}>↗</span>}</span>
                );
              })}
            </div>
            {/* Expanded description */}
            {isActive && (
              <div style={{padding:"0 18px 16px",animation:"fadeUp 0.25s ease both"}}>
                <div style={{height:1,background:`linear-gradient(90deg,rgba(${sub.glow},0.2),transparent)`,marginBottom:12}}/>
                <p style={{fontSize:12.5,color:"#7aa09a",lineHeight:1.82}}>{sub.desc}</p>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

function PlatformStack(){
  const [activeId, setActiveId] = React.useState(null);
  const [productModal, setProductModal] = React.useState(null);

  function toggle(id){
    setActiveId(prev => prev === id ? null : id);
  }

  return(
    <React.Fragment>
    <section style={{maxWidth:1100,margin:"0 auto",padding:"52px 44px 0",width:"100%"}}>
      {/* Section header removed per design update */}

      <div style={{textAlign:"center",marginBottom:36}}>
        <h2 style={{fontSize:"clamp(20px,2.8vw,32px)",fontWeight:800,color:"#fff",letterSpacing:"-0.03em",lineHeight:1.1,marginBottom:10,fontFamily:"'Syne',sans-serif"}}>
          How the platform <span style={{color:"#63AB8F"}}>layers together</span>
        </h2>
        <p style={{fontSize:14,color:"#6E9990",maxWidth:560,margin:"0 auto",lineHeight:1.75}}>
          Each layer can be sold independently or combined into a complete, integrated solution. Click any <span style={{color:"#91C4B0",fontWeight:700}}>product pill ↗</span> to explore full product details.
        </p>
      </div>

      {/* Stack */}
      <div style={{display:"flex",flexDirection:"column",gap:0,position:"relative"}}>

        {/* Left rail label */}
        <div style={{position:"absolute",left:-38,top:0,bottom:0,display:"flex",alignItems:"center",pointerEvents:"none"}}>
          <div style={{writingMode:"vertical-rl",transform:"rotate(180deg)",fontSize:9,fontWeight:800,color:"rgba(99,171,143,0.3)",letterSpacing:"0.15em",textTransform:"uppercase",whiteSpace:"nowrap"}}>
            Adding value ↑ · Building upwards
          </div>
        </div>

        <StackLayerFull layer={STACK_LAYERS[0]} isActive={activeId==="prof"} onToggle={()=>toggle("prof")} onProduct={setProductModal}/>
        <div className="stack-connector"><svg width="16" height="22" viewBox="0 0 16 22" style={{zIndex:1}}><path d="M8 0 L8 22" stroke="rgba(99,171,143,0.3)" strokeWidth="1.5" strokeDasharray="3 3"/><path d="M3 16 L8 22 L13 16" stroke="rgba(99,171,143,0.4)" strokeWidth="1.5" fill="none"/></svg></div>

        <StackLayerFull layer={STACK_LAYERS[1]} isActive={activeId==="managed"} onToggle={()=>toggle("managed")} onProduct={setProductModal}/>
        <div className="stack-connector"><svg width="16" height="22" viewBox="0 0 16 22" style={{zIndex:1}}><path d="M8 0 L8 22" stroke="rgba(99,171,143,0.3)" strokeWidth="1.5" strokeDasharray="3 3"/><path d="M3 16 L8 22 L13 16" stroke="rgba(99,171,143,0.4)" strokeWidth="1.5" fill="none"/></svg></div>

        <StackLayerSplit layer={STACK_LAYERS[2]} activeId={activeId} onToggle={toggle} onProduct={setProductModal}/>
        <div className="stack-connector"><svg width="16" height="22" viewBox="0 0 16 22" style={{zIndex:1}}><path d="M8 0 L8 22" stroke="rgba(99,171,143,0.3)" strokeWidth="1.5" strokeDasharray="3 3"/><path d="M3 16 L8 22 L13 16" stroke="rgba(99,171,143,0.4)" strokeWidth="1.5" fill="none"/></svg></div>

        <StackLayerFull layer={STACK_LAYERS[3]} isActive={activeId==="platform"} onToggle={()=>toggle("platform")} onProduct={setProductModal}/>
        <div className="stack-connector"><svg width="16" height="22" viewBox="0 0 16 22" style={{zIndex:1}}><path d="M8 0 L8 22" stroke="rgba(99,171,143,0.3)" strokeWidth="1.5" strokeDasharray="3 3"/><path d="M3 16 L8 22 L13 16" stroke="rgba(99,171,143,0.4)" strokeWidth="1.5" fill="none"/></svg></div>

        <StackLayerFull layer={STACK_LAYERS[4]} isActive={activeId==="telephony"} onToggle={()=>toggle("telephony")} onProduct={setProductModal}/>

        <div style={{textAlign:"center",marginTop:14,fontSize:11,color:"rgba(99,171,143,0.35)",letterSpacing:"0.08em",fontWeight:700}}>
          ▲ &nbsp; Foundation layer — every solution builds from here &nbsp; ▲
        </div>
      </div>
    </section>

    {/* Product Modal */}
    {productModal && (
      <ProductModal
        productName={productModal}
        onClose={()=>setProductModal(null)}
        onNavigate={name=>setProductModal(name)}
      />
    )}
    </React.Fragment>
  );
}

